CREATE TABLE `ap_supplier` ( `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT 'id', `name` varchar(128) NOT NULL COMMENT 'дҫӣеә”е•ҶеҗҚз§°', `system_code` varchar(255) NOT NULL COMMENT 'зі»з»ҹзј–з Ғ', `short_name` varchar(255) NOT NULL COMMENT 'з®Җз§°', `contact_man` varchar(255) DEFAULT NULL COMMENT 'иҒ”зі»дәә', `contact_phone` varchar(255) DEFAULT NULL COMMENT 'иҒ”зі»ж–№ејҸ', `contact_info` varchar(1000) DEFAULT NULL COMMENT 'иҒ”зі»дҝЎжҒҜ', `contact_wechat` varchar(50) DEFAULT NULL COMMENT 'иҒ”зі»еҫ®дҝЎ', `url_one` varchar(255) DEFAULT NULL COMMENT 'й“ҫжҺҘдёҖ', `url_two` varchar(255) DEFAULT NULL COMMENT 'й“ҫжҺҘдәҢ',
`email` varchar(50) DEFAULT NULL COMMENT 'йӮ®з®ұ', `address` varchar(50) DEFAULT NULL COMMENT 'ең°еқҖ', `create_by` varchar(64) DEFAULT '' COMMENT 'еҲӣе»әиҖ…', `create_time` datetime DEFAULT NULL COMMENT 'еҲӣе»әж—¶й—ҙ', `update_by` varchar(64) DEFAULT '' COMMENT 'жӣҙж–°иҖ…', `update_time` datetime DEFAULT NULL COMMENT 'жӣҙж–°ж—¶й—ҙ', `remark` varchar(500) DEFAULT NULL COMMENT 'еӨҮжіЁ', PRIMARY KEY (`id`), UNIQUE KEY `system_code` (`system_code`) ) ENGINE=InnoDB AUTO_INCREMENT=103 DEFAULT CHARSET=utf8mb4 COMMENT='дҫӣеә”е•Ҷ';
CREATE TABLE `ap_product_brand` ( `id` bigint(20) NOT NULL AUTO_INCREMENT, `name` varchar(255) DEFAULT '' COMMENT 'еҗҚз§°', `logo` varchar(255) DEFAULT '' COMMENT 'logo', `create_id` bigint(20) NOT NULL COMMENT 'еҲӣе»әиҖ…ID', `create_by` varchar(64) DEFAULT '' COMMENT 'еҲӣе»әиҖ…', `create_time` datetime DEFAULT NULL COMMENT 'еҲӣе»әж—¶й—ҙ', `update_id` bigint(20) NOT NULL COMMENT 'жӣҙж–°иҖ…ID', `update_by` varchar(64) DEFAULT '' COMMENT 'жӣҙж–°иҖ…', `update_time` datetime DEFAULT NULL COMMENT 'жӣҙж–°ж—¶й—ҙ', `remark` varchar(500) DEFAULT NULL COMMENT 'еӨҮжіЁ', PRIMARY KEY (`id`), UNIQUE KEY `ap_product_brand_name` (`name`) ) ENGINE=InnoDB AUTO_INCREMENT=106 DEFAULT CHARSET=utf8mb4 COMMENT='е“ҒзүҢеә“';
CREATE TABLE `ap_product_category` ( `id` bigint(20) NOT NULL AUTO_INCREMENT, `name` varchar(255) NOT NULL COMMENT 'еҗҚз§°', `parent_id` int(11) DEFAULT NULL COMMENT 'дёҠзә§еҲҶзұ»id', `create_id` bigint(20) NOT NULL COMMENT 'еҲӣе»әиҖ…ID', `create_by` varchar(64) DEFAULT '' COMMENT 'еҲӣе»әиҖ…', `create_time` datetime DEFAULT NULL COMMENT 'еҲӣе»әж—¶й—ҙ', `update_id` bigint(20) NOT NULL COMMENT 'жӣҙж–°иҖ…ID', `update_by` varchar(64) DEFAULT '' COMMENT 'жӣҙж–°иҖ…', `update_time` datetime DEFAULT NULL COMMENT 'жӣҙж–°ж—¶й—ҙ', `remark` varchar(500) DEFAULT NULL COMMENT 'еӨҮжіЁ', `order_num` int(11) DEFAULT '0' COMMENT 'жҺ’еәҸ', PRIMARY KEY (`id`), KEY `ap_product_category_fk_4` (`parent_id`), UNIQUE KEY `ap_product_category_name` (`name`) ) ENGINE=InnoDB AUTO_INCREMENT=1195 DEFAULT CHARSET=utf8mb4 COMMENT='е•Ҷе“ҒеҲҶзұ»';
CREATE TABLE `ap_product` ( `id` bigint(20) NOT NULL AUTO_INCREMENT, `name` varchar(255) NOT NULL COMMENT 'еҗҚз§°', `product_status` varchar(32) NOT NULL COMMENT 'зҠ¶жҖҒ', `system_code` varchar(255) DEFAULT NULL COMMENT 'зј–з Ғ', `supplier_code` varchar(255) DEFAULT NULL COMMENT 'дҫӣеә”е•Ҷзј–з Ғ',
`main_img` varchar(500) DEFAULT NULL COMMENT 'дё»еӣҫ', `show_img` longtext DEFAULT NULL COMMENT 'иҪ®ж’ӯеӣҫ', `main_content` longtext DEFAULT NULL COMMENT 'иҜҰжғ…',
`has_pdd_online` bit(1) DEFAULT b'0' COMMENT 'жӢјеӨҡеӨҡ', `pdd_id` varchar(255) DEFAULT NULL COMMENT 'жӢјеӨҡеӨҡid', `pdd_edit_url` varchar(255) DEFAULT NULL COMMENT 'жӢјеӨҡеӨҡid', `pdd_sell_count` int(10) DEFAULT '0' COMMENT 'й”ҖйҮҸ', `pdd_code` varchar(255) DEFAULT NULL COMMENT 'е•Ҷе“Ғзј–з Ғ',
`category_one_id` bigint(20) DEFAULT NULL COMMENT 'еҲҶзұ»дёҖid', `category_one_name` varchar(255) DEFAULT NULL COMMENT 'еҲҶзұ»дёҖеҗҚз§°', `category_two_id` bigint(20) DEFAULT NULL COMMENT 'еҲҶзұ»дәҢid', `category_two_name` varchar(255) DEFAULT NULL COMMENT 'еҲҶзұ»дәҢеҗҚз§°',
`unit_id` bigint(20) DEFAULT NULL COMMENT 'еҚ•дҪҚid', `unit_name` varchar(255) DEFAULT NULL COMMENT 'еҚ•дҪҚеҗҚз§°', `brand_id` bigint(20) DEFAULT NULL COMMENT 'е“ҒзүҢid', `brand_name` varchar(255) DEFAULT NULL COMMENT 'е“ҒзүҢеҗҚз§°',
`price_min` decimal(8,2) DEFAULT '0.00' COMMENT 'жңҖдҪҺд»·', `price_max` decimal(8,2) DEFAULT '0.00' COMMENT 'жңҖй«ҳд»·',
`create_by` varchar(64) DEFAULT '' COMMENT 'еҲӣе»әиҖ…', `create_time` datetime DEFAULT NULL COMMENT 'еҲӣе»әж—¶й—ҙ', `update_by` varchar(64) DEFAULT '' COMMENT 'жӣҙж–°иҖ…', `update_time` datetime DEFAULT NULL COMMENT 'жӣҙж–°ж—¶й—ҙ', `remark` varchar(500) DEFAULT NULL COMMENT 'еӨҮжіЁ', `supplier_id` bigint(20) DEFAULT NULL COMMENT 'дҫӣеә”е•Ҷid', `supplier_name` varchar(255) DEFAULT NULL COMMENT 'дҫӣеә”е•ҶеҗҚз§°', PRIMARY KEY (`id`), UNIQUE KEY `ap_product_name` (`name`), UNIQUE KEY `ap_product_supplier_code` (`supplier_code`), UNIQUE KEY `ap_product_pdd_id` (`pdd_id`), UNIQUE KEY `ap_product_system_code` (`system_code`), UNIQUE KEY `ap_product_pdd_code` (`pdd_code`) ) ENGINE=InnoDB AUTO_INCREMENT=6866 DEFAULT CHARSET=utf8mb4 COMMENT='е•Ҷе“Ғ';
CREATE TABLE `ap_product_sku` ( `id` bigint(20) NOT NULL AUTO_INCREMENT, `name` varchar(255) NOT NULL COMMENT 'еҗҚз§°', `system_code` varchar(255) DEFAULT NULL COMMENT 'зј–з Ғ', `product_id` bigint(20) DEFAULT NULL COMMENT 'д»·зӣ®id',
`cost_price` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT 'иҝӣд»·', `retail_price` decimal(12,2) DEFAULT '0.00' COMMENT 'йӣ¶е”®д»·', `control_price` decimal(12,2) DEFAULT '0.00' COMMENT 'еҲҶй”ҖжҺ§д»·', `marked_price` decimal(12,2) DEFAULT '0.00' COMMENT 'ж Үд»·', `min_price` decimal(12,2) DEFAULT '0.00' COMMENT 'жңҖдҪҺд»·', `profit` decimal(12,2) DEFAULT '0.00' COMMENT 'еҲ©ж¶Ұ', `express_price` decimal(12,2) DEFAULT '0.00' COMMENT 'зү©жөҒиҙ№з”Ё',
`stock` int(10) DEFAULT '0' COMMENT 'еә“еӯҳ', `sell_count` int(10) DEFAULT '0' COMMENT 'е·Іе”®', `has_del` bit(1) DEFAULT b'0' COMMENT 'ж Үи®°еҲ йҷӨ',
`search_cache` varchar(5000) DEFAULT NULL COMMENT 'жҗңзҙўзј“еӯҳ', `create_by` varchar(64) DEFAULT '' COMMENT 'еҲӣе»әиҖ…', `create_time` datetime DEFAULT NULL COMMENT 'еҲӣе»әж—¶й—ҙ', `update_by` varchar(64) DEFAULT '' COMMENT 'жӣҙж–°иҖ…', `update_time` datetime DEFAULT NULL COMMENT 'жӣҙж–°ж—¶й—ҙ', `remark` varchar(500) DEFAULT NULL COMMENT 'еӨҮжіЁ', UNIQUE KEY `ap_product_sku_name` (`product_id`,`name` ), UNIQUE KEY `ap_product_sku_code` (`product_id`,`system_code` ),
PRIMARY KEY (`id`),
KEY `repair_product_sku_fk_product_idx` (`product_id`), CONSTRAINT `repair_product_sku_fk_product` FOREIGN KEY (`product_id`) REFERENCES `ap_product` (`id`) ON DELETE NO ACTION ON UPDATE NO ACTION ) ENGINE=InnoDB AUTO_INCREMENT=8003 DEFAULT CHARSET=utf8mb4 COMMENT='е•Ҷе“Ғи§„ж ј';
CREATE TABLE `ap_product_unit` ( `id` bigint(20) NOT NULL AUTO_INCREMENT, `name` varchar(255) DEFAULT '' COMMENT 'еҗҚз§°', `create_by` varchar(64) DEFAULT '' COMMENT 'еҲӣе»әиҖ…', `create_time` datetime DEFAULT NULL COMMENT 'еҲӣе»әж—¶й—ҙ', `update_by` varchar(64) DEFAULT '' COMMENT 'жӣҙж–°иҖ…', `update_time` datetime DEFAULT NULL COMMENT 'жӣҙж–°ж—¶й—ҙ', `remark` varchar(500) DEFAULT NULL COMMENT 'еӨҮжіЁ', PRIMARY KEY (`id`) ) ENGINE=InnoDB AUTO_INCREMENT=155 DEFAULT CHARSET=utf8mb4 COMMENT='еҚ•дҪҚ';
